# Category: mfa_bypass

import os
import base64
from flask import Flask, render_template, request, redirect, url_for, session, flash, g
import pyotp
from functools import wraps
import qrcode
import io

app = Flask(__name__)
# A strong secret key is essential for session security.
# In production, use an environment variable: app.secret_key = os.environ.get('SECRET_KEY')
app.secret_key = os.urandom(24) 

# --- Dummy User Database ---
# In a real application, this would be a proper database.
# mfa_secret would be stored securely (e.g., encrypted) and associated with a user ID.
# For this example, 'mfa_secret' stores the base32 secret directly.
users = {
    'alice': {
        'password': 'password123',
        'mfa_secret': None # Will be set upon MFA setup
    },
    'bob': {
        'password': 'bobspassword',
        'mfa_secret': None
    }
}

# --- Decorators ---
def login_required(f):
    """
    Decorator to ensure the user is logged in via password.
    Also injects MFA status into Flask's `g` object.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session or not session.get('authenticated_password'):
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login'))
        
        g.user_id = session['user_id'] # Make user_id easily accessible in templates/views
        g.mfa_verified = session.get('mfa_verified', False) # Is MFA verified for this session?
        
        user_data = users.get(g.user_id)
        if user_data:
            g.mfa_pending_setup = user_data['mfa_secret'] is None # Has MFA secret been generated for this user?
            g.mfa_needs_verification = not g.mfa_verified and not g.mfa_pending_setup # MFA set up but not verified for this session
        else:
            # Should not happen if user_id is in session
            flash('User data not found, please re-login.', 'danger')
            return redirect(url_for('logout'))

        return f(*args, **kwargs)
    return decorated_function

# --- Routes ---

@app.route('/')
def index():
    if 'user_id' in session and session.get('authenticated_password'):
        return redirect(url_for('dashboard'))
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    """
    Handles user login with username and password.
    If successful, sets session variables and redirects to dashboard.
    MFA verification happens 'in the background' meaning the user is granted
    initial access, but prompted for MFA.
    """
    if 'user_id' in session and session.get('authenticated_password'):
        flash('You are already logged in.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']

        user_data = users.get(username)

        if user_data and user_data['password'] == password:
            session['user_id'] = username
            session['authenticated_password'] = True
            session['mfa_verified'] = False # MFA is not yet verified for this new session

            # Simulate "background" MFA initiation if MFA is configured for the user.
            # This means the user is now logged in via password, can access most resources,
            # but will be prompted to complete MFA.
            if user_data['mfa_secret']:
                # In a real app, this is where you might trigger an async task
                # to send an SMS/email/push notification to the user's registered device.
                # For TOTP, it just implies the user *can* verify it whenever they navigate to /verify-mfa.
                flash('Login successful. Please complete Two-Factor Authentication for full security.', 'info')
            else:
                flash('Login successful. Please set up Two-Factor Authentication for enhanced security.', 'info')

            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password', 'danger')

    return render_template('login.html')

@app.route('/dashboard')
@login_required
def dashboard():
    """
    Protected resource accessible after password login.
    Displays a banner if MFA is pending setup or verification for the current session.
    """
    return render_template('dashboard.html',
                           user_id=g.user_id,
                           mfa_verified=g.mfa_verified,
                           mfa_needs_verification=g.mfa_needs_verification,
                           mfa_pending_setup=g.mfa_pending_setup)

@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    """
    Allows users to set up MFA (generate QR code) or verify an existing MFA setup.
    If MFA is successfully verified, the session is marked as 'mfa_verified'.
    """
    user_id = g.user_id
    user_data = users.get(user_id)

    if not user_data:
        flash('User data not found.', 'danger')
        return redirect(url_for('logout'))

    if g.mfa_verified:
        flash('Two-Factor Authentication is already verified for this session.', 'success')
        return redirect(url_for('dashboard'))

    mfa_secret = user_data.get('mfa_secret')
    otp_uri = None
    qr_code_base64 = None

    if request.method == 'POST':
        otp_code = request.form['otp_code']
        if not mfa_secret:
            flash('MFA not set up for your account. Please set it up first by reloading this page.', 'danger')
            return redirect(url_for('verify_mfa')) # Redirect back to setup state

        totp = pyotp.TOTP(mfa_secret)
        if totp.verify(otp_code):
            session['mfa_verified'] = True
            flash('Two-Factor Authentication successfully verified!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid OTP code. Please try again.', 'danger')

    # GET request logic: Display setup or verification form
    if not mfa_secret:
        # MFA not yet set up for this user. Generate a new secret.
        new_secret = pyotp.random_base32()
        users[user_id]['mfa_secret'] = new_secret # Store new secret in our dummy DB
        mfa_secret = new_secret # Use the new secret for this render

        # Generate OTP URI for authenticator apps (e.g., Google Authenticator)
        otp_uri = pyotp.totp.TOTP(mfa_secret).provisioning_uri(
            name=user_id,
            issuer_name="MyFlaskMFAApp"
        )
        
        # Generate QR code image as base64 for embedding in HTML
        try:
            img = qrcode.make(otp_uri)
            buf = io.BytesIO()
            img.save(buf, format="PNG")
            qr_code_base64 = base64.b64encode(buf.getvalue()).decode('utf-8')
        except Exception as e:
            flash(f"Could not generate QR code: {e}. Please manually copy the key.", 'warning')
            qr_code_base64 = None

        flash('Please scan the QR code with your authenticator app and enter the code below to verify.', 'info')
    
    # If MFA is set up (or just got set up), show the verification form
    return render_template('verify_mfa.html',
                           mfa_secret_exists=mfa_secret is not None,
                           otp_uri=otp_uri,
                           qr_code_base64=qr_code_base64,
                           mfa_secret_value=mfa_secret if not g.mfa_verified else None # Only show secret during initial setup for security
                           )

@app.route('/protected-sensitive')
@login_required
def protected_sensitive():
    """
    An example of a highly sensitive route that strictly requires MFA verification.
    If MFA is not verified for the current session, it will redirect to /verify-mfa.
    """
    if not g.mfa_verified:
        flash('Access to sensitive resources requires Two-Factor Authentication verification.', 'danger')
        return redirect(url_for('verify_mfa'))
    return render_template('protected_sensitive.html', user_id=g.user_id)

@app.route('/logout')
def logout():
    """Clears the session and logs the user out."""
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('login'))

